<?php namespace App\Providers; use Illuminate\Cache\RateLimiting\Limit; use Illuminate\Support\Facades\RateLimiter; use Illuminate\Foundation\Support\Providers\RouteServiceProvider as ServiceProvider; use Illuminate\Http\Request; class RateLimiterServiceProvider extends ServiceProvider { public function boot(): void { RateLimiter::for('api', function (Request $request) { $user = $request->user(); if ($user && $user->hasRole('lawyer')) { return Limit::perMinute(1000)->by($user->id); } if ($user && $user->hasRole('client')) { return Limit::perMinute(200)->by($user->id); } return Limit::perMinute(60)->by($request->ip()); }); } public function register(): void { } }